class Solution:
    def findMaxK(self, nums):
        best = -1
        for i in range(len(nums)):
            for j in range(len(nums)):
                if nums[i] > 0 and nums[j] == -nums[i]:
                    if nums[i] > best:
                        best = nums[i]
        return best

